import ray
from typing import Callable

ray.init(ignore_reinit_error=True)

class Model:
    def __init__(self, weights):
        self.weights = weights
    def predict(self, x):
        return sum(self.weights[c] for c in x)

class Runner:
    def __init__(self, model: Model):
        self._model = model
        # BUG: wrapping a ray.remote around a local closure that captures self._model
        # — Ray tries to pickle the closure and fails.
        self._score = ray.remote(self._build_scorer())

    def _build_scorer(self) -> Callable:
        model = self._model
        def score_one(batch):
            return [model.predict(x) for x in batch]
        return score_one

    def run(self, batches):
        futs = [self._score.remote(b) for b in batches]
        return ray.get(futs)

if __name__ == '__main__':
    r = Runner(Model({'a': 1, 'b': 2}))
    print(r.run([[('a','b')], [('a','a','b')]]))
